package org.example.matrix.search;

import javax.jcr.Session;
import javax.jcr.query.Query;
import javax.jcr.query.QueryManager;
import javax.jcr.query.QueryResult;
import javax.jcr.NodeIterator;

public class MatrixSearch {

    public void findTheOne(Session session) throws Exception {
        QueryManager qm = session.getWorkspace().getQueryManager();

        String sql = "SELECT * FROM [nt:unstructured] AS node " +
                     "WHERE ISDESCENDANTNODE(node, '/content/sling-matrix') " +
                     "AND node.[matrixRole] = 'The One'";

        Query query = qm.createQuery(sql, Query.JCR_SQL2);
        query.setLimit(10);

        QueryResult result = query.execute();
        NodeIterator nodes = result.getNodes();

        while (nodes.hasNext()) {
            System.out.println("Found: " + nodes.nextNode().getPath());
        }
    }
}
